def gen(rng, size):
    n = max(2, size)
    seats = [1 if rng.random() < 0.3 else 0 for _ in range(n)]
    if 1 not in seats:
        seats[rng.randrange(n)] = 1
    if 0 not in seats:
        seats[rng.randrange(n)] = 0
    return [seats]

