class Solution:
    def maxDistToClosest(self, seats):
        n = len(seats)
        occupied = [i for i, v in enumerate(seats) if v == 1]
        best = 0
        for i in range(n):
            if seats[i] == 0:
                d = min(abs(i - j) for j in occupied)
                best = max(best, d)
        return best

