var maxDistToClosest = function(seats) {
    const n = seats.length;
    let prev = -1, best = 0;
    for (let i = 0; i < n; i++) {
        if (seats[i] === 1) {
            if (prev === -1) best = Math.max(best, i);
            else best = Math.max(best, Math.floor((i - prev) / 2));
            prev = i;
        }
    }
    best = Math.max(best, n - 1 - prev);
    return best;
};
